module TopModule (input clk, input reset, output shift_ena); logic shift_ena_d; reg [1:0] state; logic [1:0] count; localparam STATE_A = 2'd0, STATE_B = 2'd1, STATE_C = 2'd2, STATE_D = 2'd3; localparam COUNTER_MAX = 2'd3; initial begin state = STATE_A; count = 0; end always @(posedge clk) begin if (reset) begin state <= STATE_A; count <= 0; end else begin case (state) STATE_A: state <= STATE_B; STATE_B: begin if (count == COUNTER_MAX) state <= STATE_D; else count <= count + 1; end STATE_C: state <= STATE_D; STATE_D: state <= STATE_D; endcase end end always @(*) shift_ena_d = (state != STATE_D); assign shift_ena = shift_ena_d; endmodule